SELECT BNR_GRP_ID AS bnrGrpId , SITE_CD AS siteCd , LANG_SE AS langSe , BNR_GRP_NM AS bnrGrpNm , BNR_GRP_DESC AS bnrGrpDesc , USE_YN AS useYn , SORT AS sort , TO_CHAR(CRT_AT, 'YYYY-MM-DD HH24:MI:SS') AS crtAt , TO_CHAR(UPD_AT, 'YYYY-MM-DD HH24:MI:SS') AS updAt FROM CMS_BNR_GRP
SITE_CD = #{siteCd}
AND LANG_SE = #{langSe}
AND USE_YN = #{useYn}
ORDER BY SORT ASC, BNR_GRP_ID ASC

