mapper.update:
UPDATE CMS_BNR_GRP
   SET BNR_GRP_NM   = #{vo.bnrGrpNm}
     , BNR_GRP_DESC = #{vo.bnrGrpDesc}
     , USE_YN        = NVL(#{vo.useYn}, USE_YN)
     , SORT          = #{vo.sort}
     , 
 WHERE SITE_CD       = #{siteCd}
   AND BNR_GRP_ID    = #{bnrGrpId}
   AND LANG_SE       = #{langSe}

mapper.delete:
