 WHERE SITE_CD    = #{siteCd}
   AND BNR_GRP_ID = #{bnrGrpId}
   AND LANG_SE    = #{langSe}

mapper.select:
SELECT BNR_ID AS bnrId , BNR_GRP_ID AS bnrGrpId , SITE_CD AS siteCd , LANG_SE AS langSe , BNR_NM AS bnrNm , BNR_DESC AS bnrDesc , AFILE_ID AS afileId , ORD AS ord , PUB_ST_YMD AS pubStYmd , PUB_ST_HR AS pubStHr , PUB_END_YMD AS pubEndYmd , PUB_END_HR AS pubEndHr , USE_YN AS useYn , BNR_SE AS bnrSe , BNR_SZ_SE AS bnrSzSe , BNR_URL AS bnrUrl , DEL_YN AS delYn , BNR_RMK AS bnrRmk , TO_CHAR(CRT_AT, 'YYYY-MM-DD HH24:MI:SS') AS crtAt , TO_CHAR(UPD_AT, 'YYYY-MM-DD HH24:MI:SS') AS updAt FROM CMS_BNR
SITE_CD = #{siteCd}
AND BNR_GRP_ID = #{bnrGrpId}
AND LANG_SE = #{langSe}
AND USE_YN = #{useYn}
ORDER BY ORD ASC, BNR_ID ASC

mapper.insert:
