    BNR_ID
  , BNR_GRP_ID
  , SITE_CD
  , LANG_SE
  , BNR_NM
  , BNR_DESC
  , AFILE_ID
  , ORD
  , PUB_ST_YMD
  , PUB_ST_HR
  , PUB_END_YMD
  , PUB_END_HR
  , USE_YN
  , BNR_SE
  , BNR_SZ_SE
  , BNR_URL
  , DEL_YN
  , BNR_RMK
  , 
) VALUES (
    #{bnrId}
  , #{bnrGrpId}
  , #{siteCd}
  , #{langSe}
  , #{bnrNm}
  , #{bnrDesc}
  , #{afileId}
  , #{ord}
  , #{pubStYmd}
  , #{pubStHr}
  , #{pubEndYmd}
  , #{pubEndHr}
  , NVL(#{useYn}, 'Y')
  , #{bnrSe}
  , #{bnrSzSe}
  , #{bnrUrl}
  , NVL(#{delYn}, 'N')
  , #{bnrRmk}
  , 
)

mapper.update:
UPDATE CMS_BNR
   SET BNR_NM      = #{vo.bnrNm}
     , BNR_DESC    = #{vo.bnrDesc}
     , AFILE_ID    = #{vo.afileId}
     , ORD         = #{vo.ord}
     , PUB_ST_YMD  = #{vo.pubStYmd}
     , PUB_ST_HR   = #{vo.pubStHr}
     , PUB_END_YMD = #{vo.pubEndYmd}
     , PUB_END_HR  = #{vo.pubEndHr}
     , USE_YN      = NVL(#{vo.useYn}, USE_YN)
     , BNR_SE      = #{vo.bnrSe}
     , BNR_SZ_SE   = #{vo.bnrSzSe}
     , BNR_URL     = #{vo.bnrUrl}
     , DEL_YN      = NVL(#{vo.delYn}, DEL_YN)
     , BNR_RMK     = #{vo.bnrRmk}
     , 
 WHERE SITE_CD     = #{siteCd}
   AND BNR_GRP_ID  = #{bnrGrpId}
   AND BNR_ID      = #{bnrId}
   AND LANG_SE     = #{langSe}

